css:
.loader {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 6px;
      height: 40px;
    }
    .loader i {
      display: block;
      width: 6px;
      height: 40px;
      border-radius: 999px;
      background: linear-gradient(180deg, var(--loader-color), var(--loader-secondary-color));
      transform-origin: center bottom;
      animation: barPulse 0.91s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.09s; }
.loader i:nth-child(3) { animation-delay: 0.18s; }
.loader i:nth-child(4) { animation-delay: 0.27s; }
    @keyframes barPulse { 0%, 100% { opacity: .25; transform: scaleY(.5); } 45% { opacity: 1; transform: scaleY(1); } }
